<script setup>
defineProps({items:{type:Array,default:()=>[]},modelValue:{type:String,default:''},compact:Boolean})
defineEmits(['update:modelValue'])
</script>
<template><div class="pill-nav" :class="{compact}" role="tablist"><span class="pill-slider" :style="{width:`${100/items.length}%`,transform:`translateX(${Math.max(0,items.findIndex(i=>i.id===modelValue))*100}%)`}"></span><button v-for="item in items" :key="item.id" :class="{active:modelValue===item.id}" role="tab" :aria-selected="modelValue===item.id" @click="$emit('update:modelValue',item.id)"><span class="hover-orb"></span><span class="pill-copy">{{ item.icon }} {{ item.label }}</span></button></div></template>
<style scoped>.pill-nav{position:relative;display:grid;grid-auto-flow:column;grid-auto-columns:1fr;min-width:320px;padding:4px;border:1px solid var(--border);border-radius:999px;background:var(--surface);box-shadow:0 8px 25px var(--shadow);isolation:isolate;transition:background .3s ease,border-color .3s ease}.pill-slider{position:absolute;z-index:-1;top:4px;bottom:4px;left:4px;border-radius:999px;background:var(--accent-gradient);box-shadow:0 7px 18px var(--shadow);transition:transform .38s cubic-bezier(.2,.9,.2,1),width .3s}.pill-nav button{position:relative;min-width:92px;padding:10px 15px;overflow:hidden;border:0;border-radius:999px;color:var(--muted);background:none;font-size:12px;font-weight:700;white-space:nowrap}.pill-copy{position:relative;z-index:2}.hover-orb{position:absolute;z-index:1;left:50%;bottom:-55px;width:110px;height:80px;border-radius:50%;background:color-mix(in srgb,var(--yellow) 42%,transparent);transform:translateX(-50%) scale(0);transition:transform .32s ease}.pill-nav button:hover .hover-orb{transform:translateX(-50%) scale(1)}.pill-nav button.active{color:var(--on-accent)}.compact{min-width:0;width:100%}.compact button{min-width:0;padding:9px 8px}@media(max-width:600px){.pill-nav{min-width:0;width:100%}.pill-nav button{min-width:0;padding:9px 7px}.pill-copy{font-size:11px}}</style>
